  function renderWeather() {
    return (
      <section style={sectionStyle}>
        <SectionHeader
          eyebrow="7-Day Forecast"
          title="Weather / Irrigation Planning"
          detail="Real 7-day forecast with irrigation recommendations."
          right={
            <button
              type="button"
              onClick={() => void loadWeather()}
              style={goldButtonStyle}
            >
              Refresh Weather
            </button>
          }
        />

        <div style={stackStyle}>
          <div style={noticeStyle}>
            <strong>{weatherStatus}</strong>
            <p style={mutedSmallStyle}>
              Forecast location is the 2000 area. Uses rain chance, rain amount,
              wind, and ET0 for irrigation planning.
            </p>
          </div>

          <div style={weatherStripStyle}>
            {weatherDays.map((day) => (
              <button
                key={day.date}
                type="button"
                onClick={() => setSelectedWeatherDate(day.date)}
                style={{
                  ...weatherCardStyle,
                  borderColor:
                    day.date === selectedWeather?.date
                      ? colors.gold
                      : colors.line,
                  boxShadow:
                    day.date === selectedWeather?.date
                      ? "0 18px 38px rgba(201,154,61,0.24)"
                      : "0 12px 26px rgba(15,23,42,0.06)",
                }}
              >
                <div style={weatherCardTopStyle}>
                  <div>
                    <strong>
                      {new Date(`${day.date}T12:00:00`).toLocaleDateString(
                        undefined,
                        { weekday: "short" },
                      )}
                    </strong>
                    <p style={mutedSmallStyle}>
                      {new Date(`${day.date}T12:00:00`).toLocaleDateString(
                        undefined,
                        { month: "short", day: "numeric" },
                      )}
                    </p>
                  </div>
                  <div style={weatherIconStyle}>{weatherIcon(day.code)}</div>
                </div>

                <div style={weatherTempStyle}>{day.high}°</div>
                <div style={weatherLowStyle}>{day.low}° low</div>

                <div style={weatherBarTrackStyle}>
                  <div
                    style={{
                      ...weatherBarFillStyle,
                      width: `${Math.max(12, Math.min(100, day.precipChance))}%`,
                    }}
                  />
                </div>

                <div style={weatherMiniGridStyle}>
                  <span>Rain {day.precipChance}%</span>
                  <span>{day.precipAmount}"</span>
                  <span>Wind {day.windMax}</span>
                  <span>ET0 {day.et0}"</span>
                </div>

                <p style={weatherAdviceSmallStyle}>{irrigationAdvice(day)}</p>
              </button>
            ))}
          </div>
        </div>
      </section>
    );
  }

  function renderManuals() {
    const normalizedSearch = manualSearch.trim().toLowerCase();
    const filteredManuals = [...manualRecords]
      .filter((manual) =>
        manualCategoryFilter === "All" ? true : manual.category === manualCategoryFilter,
      )
      .filter((manual) => {
        if (!normalizedSearch) return true;
        return [
          manual.title,
          manual.category,
          manual.manufacturer,
          manual.model,
          manual.documentNumber,
          manual.linkedAssetName,
          manual.sourceLabel,
          manual.notes,
        ]
          .join(" ")
          .toLowerCase()
          .includes(normalizedSearch);
      })
      .sort((a, b) => a.category.localeCompare(b.category) || a.title.localeCompare(b.title));

    const selectedManual = selectedManualId
      ? manualRecords.find((item) => item.id === selectedManualId) || null
      : null;
    const activeManual = selectedManual || manualDraft;
    const isEditing = Boolean(selectedManual);

    function startNewManual() {
      setSelectedManualId("");
      setManualDraft(blankManual());
      setManualMessage("Ready for a new manual. Paste a PDF link or upload a file.");
    }

    function updateActiveManual(patch: Partial<ManualRecord>) {
      if (isEditing && selectedManual) {
        setManualRecords((current) =>
          current.map((item) =>
            item.id === selectedManual.id ? normalizeManualRecord({ ...item, ...patch }) : item,
          ),
        );
      } else {
        setManualDraft((current) => normalizeManualRecord({ ...current, ...patch, id: "" }));
      }
    }

    function saveManual() {
      const prepared = normalizeManualRecord({
        ...activeManual,
        id: activeManual.id || `manual-${Date.now()}`,
        linkedAssetName:
          assetRecords.find((asset) => asset.id === activeManual.linkedAssetId)?.name ||
          activeManual.linkedAssetName ||
          "",
      });
      if (!prepared.title.trim()) {
        setManualMessage("Add a manual title before saving.");
        return;
      }
      const next = manualRecords.some((item) => item.id === prepared.id)
        ? manualRecords.map((item) => (item.id === prepared.id ? prepared : item))
        : [prepared, ...manualRecords];
      setManualRecords(next);
      saveStoredArray(storageKeys.manuals[0], next);
      setSelectedManualId("");
      setManualDraft(blankManual());
      setManualMessage("Manual saved. The entry box is clear for the next manual.");
    }

    function deleteManual(id: string) {
      if (!window.confirm("Delete this manual from Atlas?")) return;
      const next = manualRecords.filter((item) => item.id !== id);
      setManualRecords(next);
      saveStoredArray(storageKeys.manuals[0], next);
      setSelectedManualId("");
      setManualDraft(blankManual());
      setManualMessage("Manual deleted.");
    }

    async function addManualFiles(fileList: FileList | null) {
      if (!fileList?.length) return;
      const records = await Promise.all(Array.from(fileList).map(fileToUploadedRecord));
      updateActiveManual({ files: [...(activeManual.files || []), ...records] });
      setManualMessage(`${records.length} file(s) attached. Press Save Manual.`);
    }

    return (
      <ListDrawerLayout
        eyebrow="Manual Library"
        title="Manuals"
        detail="Owner manuals, installation guides, service documents, wiring diagrams, parts catalogs, specifications, warranties, and safety documents organized by category."
        isMobile={isMobile}
        right={
          <button type="button" onClick={startNewManual} style={goldButtonStyle}>
            Add Manual
          </button>
        }
        list={
          <div style={stackStyle}>
            <div style={cardStyle}>
              <div style={eyebrowStyle}>Find Manuals</div>
              <input
                value={manualSearch}
                onChange={(event) => setManualSearch(event.currentTarget.value)}
                placeholder="Search title, asset, manufacturer, model, document number..."
                style={inputStyle}
              />
              <select
                value={manualCategoryFilter}
                onChange={(event) =>
                  setManualCategoryFilter(event.currentTarget.value as ManualCategory | "All")
                }
                style={{ ...inputStyle, marginTop: 10 }}
              >
                <option value="All">All manual categories</option>
                {manualCategories.map((category) => (
                  <option key={category} value={category}>{category}</option>
                ))}
              </select>
              <p style={mutedSmallStyle}>{filteredManuals.length} manual(s)</p>
            </div>

            <div style={cardStyle}>
              <div style={manualListHeaderStyle}>
                <span>Manual</span>
                <span>Asset</span>
                <span>File</span>
              </div>

              {filteredManuals.length ? (
                <div style={manualCompactListStyle}>
                  {filteredManuals.map((manual) => (
                    <button
                      key={manual.id}
                      type="button"
                      onClick={() => {
                        setSelectedManualId(manual.id);
                        setManualMessage("Editing selected manual.");
                      }}
                      style={{
                        ...manualCompactRowStyle,
                        borderColor:
                          selectedManualId === manual.id ? colors.gold : "transparent",
                        background:
                          selectedManualId === manual.id
                            ? "rgba(201,154,61,0.10)"
                            : "#FFFFFF",
                      }}
                    >
                      <span style={manualCompactTitleStyle}>
                        {manual.title}
                        <small style={manualCompactMetaStyle}>
                          {[manual.category, manual.manufacturer, manual.model]
                            .filter(Boolean)
                            .join(" · ")}
                        </small>
                      </span>

                      <span style={manualCompactAssetStyle}>
                        {manual.linkedAssetName || "Not linked"}
                      </span>

                      <span style={manualCompactFileStyle}>
                        {manual.href || manual.files.length ? "PDF" : "—"}
                      </span>
                    </button>
                  ))}
                </div>
              ) : (
                <p style={mutedSmallStyle}>No manuals match this search.</p>
              )}
            </div>
          </div>
        }
        drawer={
          <div style={stackStyle}>
            <h3 style={editorHeaderStyle}>{isEditing ? "Edit Manual" : "Add Manual"}</h3>
            <p style={mutedSmallStyle}>{manualMessage}</p>
            <div style={formGridStyle}>
              <Field label="Manual title" value={activeManual.title} onChange={(title) => updateActiveManual({ title })} placeholder="Paste or type the official title" />
              <label style={{ display: "grid", gap: 6 }}>
                <span style={fieldLabelStyle}>Category</span>
                <select value={activeManual.category} onChange={(event) => updateActiveManual({ category: event.currentTarget.value as ManualCategory })} style={inputStyle}>
                  {manualCategories.map((category) => <option key={category} value={category}>{category}</option>)}
                </select>
              </label>
              <Field label="Manufacturer" value={activeManual.manufacturer} onChange={(manufacturer) => updateActiveManual({ manufacturer })} />
              <Field label="Model" value={activeManual.model} onChange={(model) => updateActiveManual({ model })} />
              <Field label="Document number" value={activeManual.documentNumber} onChange={(documentNumber) => updateActiveManual({ documentNumber })} />
              <label style={{ display: "grid", gap: 6 }}>
                <span style={fieldLabelStyle}>Linked asset</span>
                <select
                  value={activeManual.linkedAssetId || ""}
                  onChange={(event) => {
                    const asset = assetRecords.find((item) => item.id === event.currentTarget.value);
                    updateActiveManual({ linkedAssetId: event.currentTarget.value, linkedAssetName: asset?.name || "" });
                  }}
                  style={inputStyle}
                >
                  <option value="">Not linked</option>
                  {byName(assetRecords).map((asset) => <option key={asset.id} value={asset.id}>{asset.name}</option>)}
                </select>
              </label>
              <Field label="Official source" value={activeManual.sourceLabel} onChange={(sourceLabel) => updateActiveManual({ sourceLabel })} placeholder="Official BRP Operator Guides" />
              <Field label="Manual / PDF web link" value={activeManual.href} onChange={(href) => updateActiveManual({ href })} placeholder="Paste the online PDF URL here" />
              <Field label="Notes" value={activeManual.notes} onChange={(notes) => updateActiveManual({ notes })} multiline />
            </div>

            <label style={uploadButtonStyle}>
              <strong>Upload a PDF or manual file</strong>
              <span style={mutedSmallStyle}>Choose one or more files from your computer or phone.</span>
              <input type="file" accept="application/pdf,image/*,.doc,.docx" multiple onChange={(event) => void addManualFiles(event.currentTarget.files)} />
            </label>

            {activeManual.files.length ? (
              <div style={cardStyle}>
                <div style={eyebrowStyle}>Attached Files</div>
                {activeManual.files.map((file) => (
                  <button key={file.id} type="button" onClick={() => openUploadedFile(file)} style={rowButtonStyle}>
                    <strong>{file.name}</strong>
                  </button>
                ))}
              </div>
            ) : null}

            <div style={buttonRowStyle}>
              <button type="button" onClick={saveManual} style={goldButtonStyle}>Save Manual</button>
              {activeManual.href ? (
                <a href={activeManual.href} target="_blank" rel="noreferrer" style={{ ...secondaryButtonStyle, textDecoration: "none", display: "inline-flex", alignItems: "center" }}>Open Manual</a>
              ) : null}
              {activeManual.href ? (
                <button type="button" onClick={() => void navigator.clipboard.writeText(activeManual.href)} style={secondaryButtonStyle}>Copy Link</button>
              ) : null}
              {isEditing && selectedManual ? (
                <button type="button" onClick={() => deleteManual(selectedManual.id)} style={dangerButtonStyle}>Delete</button>
              ) : null}
            </div>
          </div>
        }
      />
    );
  }

  function renderDocuments() {
    const normalizedDocumentSearch = documentSearch.trim().toLowerCase();
    const sortedDocuments = [...allDocuments].sort(
      (a, b) =>
        a.title.localeCompare(b.title) ||
        String(b.createdAt || "").localeCompare(String(a.createdAt || "")),
    );
    const searchableDocuments = sortedDocuments.filter((doc) => {
      if (!normalizedDocumentSearch) return true;
      const fileNames = (doc.files || []).map((file) => file.name).join(" ");
      return [
        doc.title,
        doc.type,
        doc.area,
        doc.targetType,
        doc.targetName,
        doc.notes,
        doc.pastedText,
        fileNames,
      ]
        .join(" ")
        .toLowerCase()
        .includes(normalizedDocumentSearch);
    });

    const selectedDocument =
      searchableDocuments.find((doc) => doc.id === selectedDocumentId) || null;
    const selectedTargetKind = (selectedDocument?.targetType ||
      "General") as IntakeTargetKind;
    const selectedTargetOptions = documentTargetOptionsFor(selectedTargetKind);

    function retargetSelectedDocument(kind: IntakeTargetKind) {
      if (!selectedDocument) return;
      const options = documentTargetOptionsFor(kind);
      const nextId = kind === "General" ? "" : options[0]?.id || "";
      const nextName = targetNameFor(kind, nextId);
      updateSelectedDocument(selectedDocument.id, {
        targetType: kind,
        targetId: nextId,
        targetName: nextName,
        area: nextName,
        linkedAssetId: kind === "Asset" ? nextId : undefined,
        linkedVendorId: kind === "Vendor" ? nextId : undefined,
      });
    }

    function retargetSelectedRecord(id: string) {
      if (!selectedDocument) return;
      const nextName = targetNameFor(selectedTargetKind, id);
      updateSelectedDocument(selectedDocument.id, {
        targetId: id,
        targetName: nextName,
        area: nextName,
        linkedAssetId: selectedTargetKind === "Asset" ? id : undefined,
        linkedVendorId: selectedTargetKind === "Vendor" ? id : undefined,
      });
    }

    return (
      <ListDrawerLayout
        eyebrow="Document Vault"
        title="Documents / Photos"
        detail="Search, open, edit, delete, zoom, and sync paperwork, photos, scans, PDFs, receipts, invoices, notes, and screenshots between phone and desktop."
        isMobile={isMobile}
        right={
          <button
            type="button"
            onClick={() => setScreen("intake")}
            style={goldButtonStyle}
          >
            Add Document
          </button>
        }
        list={
          <div style={stackStyle}>
            <div style={cardStyle}>
              <div style={eyebrowStyle}>Look Up Documents</div>
              <input
                value={documentSearch}
                onChange={(event) =>
                  setDocumentSearch(event.currentTarget.value)
                }
                placeholder="Search title, vendor, asset, notes, file name..."
                style={inputStyle}
              />
              <div style={{ ...buttonRowStyle, marginTop: 10 }}>
                <button
                  type="button"
                  onClick={() => void refreshDocumentVault()}
                  style={secondaryButtonStyle}
                >
                  Refresh Vault
                </button>
                <button
                  type="button"
                  onClick={() => setScreen("intake")}
                  style={goldButtonStyle}
                >
                  Add Document
                </button>
              </div>
              <p style={mutedSmallStyle}>
                {searchableDocuments.length} matching document(s), sorted A–Z.
              </p>
              <p style={mutedSmallStyle}>{documentSyncStatus}</p>
            </div>

            {!searchableDocuments.length ? (
              <div style={noticeStyle}>
                <strong>No saved documents found.</strong>
                <p style={mutedSmallStyle}>
                  Use Add Document to take a phone photo, upload a PDF/image, or
                  paste notes and link them to an Atlas record.
                </p>
                <button
                  type="button"
                  onClick={() => setScreen("intake")}
                  style={goldButtonStyle}
                >
                  Add Document
                </button>
              </div>
            ) : (
              <div style={listStyle}>
                {searchableDocuments.map((document) => {
                  const fileCount = (document.files || []).length;
                  const hasPreview =
                    fileCount > 0 ||
                    Boolean(document.pastedText || document.href);
                  return (
                    <button
                      key={document.id}
                      type="button"
                      onClick={() => setSelectedDocumentId(document.id)}
                      style={{
                        ...rowButtonStyle,
                        borderColor:
                          selectedDocument?.id === document.id
                            ? colors.gold
                            : colors.line,
                        boxShadow:
                          selectedDocument?.id === document.id
                            ? "0 14px 30px rgba(201,154,61,0.18)"
                            : rowButtonStyle.boxShadow,
                      }}
                    >
                      <div style={{ minWidth: 0 }}>
                        <strong>{document.title}</strong>
                        <p style={mutedSmallStyle}>
                          {document.type} · {document.area}
                        </p>
                        {document.targetType ? (
                          <p style={mutedSmallStyle}>
                            Linked to {document.targetType}:{" "}
                            {document.targetName || document.area}
                          </p>
                        ) : null}
                        <p style={mutedSmallStyle}>
                          {hasPreview
                            ? `${fileCount} file(s) / preview available`
                            : "Text-only record"}
                        </p>
                      </div>
                    </button>
                  );
                })}
              </div>
            )}
          </div>
        }
        drawer={
          <div>
            {selectedDocument ? (
              <div style={stackStyle}>
                <div
                  style={{
                    display: "flex",
                    alignItems: "flex-start",
                    justifyContent: "space-between",
                    gap: 12,
                  }}
                >
                  <div>
                    <h3 style={editorHeaderStyle}>
                      {selectedDocument.title.trim() || "Document"}
                    </h3>
                    <p style={mutedSmallStyle}>
                      {selectedDocument.createdAt
                        ? `Saved ${new Date(selectedDocument.createdAt).toLocaleString()}`
                        : "Saved document"}
                    </p>
                  </div>
                  <button
                    type="button"
                    onClick={() =>
                      void deleteSelectedDocument(selectedDocument)
                    }
                    style={tinyDangerButtonStyle}
                    title="Delete document"
                  >
                    × Delete
                  </button>
                </div>

                <div style={formGridStyle}>
                  <Field
                    label="Title"
                    value={selectedDocument.title}
                    onChange={(value) =>
                      updateSelectedDocument(selectedDocument.id, {
                        title: value,
                      })
                    }
                  />
                  <Field
                    label="Type"
                    value={selectedDocument.type}
                    onChange={(value) =>
                      updateSelectedDocument(selectedDocument.id, {
                        type: value,
                      })
                    }
                    placeholder="Invoice, Manual, Photo, Receipt, Estimate..."
                  />
                  <label style={{ display: "grid", gap: 6, minWidth: 0 }}>
                    <span style={fieldLabelStyle}>Linked section</span>
                    <select
                      value={selectedTargetKind}
                      onChange={(event) =>
                        retargetSelectedDocument(
                          event.currentTarget.value as IntakeTargetKind,
                        )
                      }
                      style={inputStyle}
                    >
                      {(
                        [
                          "Asset",
                          "Location",
                          "Vendor",
                          "Work Order",
                          "Map Label",
                          "General",
                        ] as IntakeTargetKind[]
                      ).map((kind) => (
                        <option key={kind} value={kind}>
                          {kind}
                        </option>
                      ))}
                    </select>
                  </label>
                  {selectedTargetKind !== "General" ? (
                    <label style={{ display: "grid", gap: 6, minWidth: 0 }}>
                      <span style={fieldLabelStyle}>Linked record</span>
                      <select
                        value={selectedDocument.targetId || ""}
                        onChange={(event) =>
                          retargetSelectedRecord(event.currentTarget.value)
                        }
                        style={inputStyle}
                      >
                        {selectedTargetOptions.map((option) => (
                          <option key={option.id} value={option.id}>
                            {option.name}
                          </option>
                        ))}
                      </select>
                    </label>
                  ) : null}
                  <Field
                    label="Notes"
                    value={selectedDocument.notes || ""}
                    onChange={(value) =>
                      updateSelectedDocument(selectedDocument.id, {
                        notes: value,
                      })
                    }
                    multiline
                    placeholder="What is this, why it matters, follow-up needed..."
                  />
                  <Field
                    label="Pasted text / copied paperwork"
                    value={selectedDocument.pastedText || ""}
                    onChange={(value) =>
                      updateSelectedDocument(selectedDocument.id, {
                        pastedText: value,
                      })
                    }
                    multiline
                    placeholder="Paste copied text, email content, invoice notes, serial info, etc."
                  />
                </div>

                <div style={buttonRowStyle}>
                  <button
                    type="button"
                    onClick={() => void saveSelectedDocument(selectedDocument)}
                    style={goldButtonStyle}
                  >
                    Save Changes
                  </button>
                  {selectedDocument.targetType &&
                  selectedDocument.targetType !== "General" ? (
                    <button
                      type="button"
                      onClick={() => openDocumentTarget(selectedDocument)}
                      style={secondaryButtonStyle}
                    >
                      Open Linked Record
                    </button>
                  ) : null}
                  <button
                    type="button"
                    onClick={() => setSelectedDocumentId("")}
                    style={secondaryButtonStyle}
                  >
                    Close
                  </button>
                </div>

                {selectedDocument.files?.length ? (
                  <div>
                    <div style={eyebrowStyle}>Files</div>
                    <div style={photoGridStyle}>
                      {selectedDocument.files.map((file) => (
                        <div key={file.id} style={photoCardStyle}>
                          <button
                            type="button"
                            onClick={() => openUploadedFile(file)}
                            style={{
                              border: 0,
                              background: "transparent",
                              padding: 0,
                              textAlign: "left",
                              cursor: "pointer",
                            }}
                          >
                            {file.dataUrl?.startsWith("data:image/") ? (
                              <img
                                src={file.dataUrl}
                                alt={file.name}
                                style={photoStyle}
                              />
                            ) : (
                              <div style={fileTileStyle}>
                                {file.type?.includes("pdf") ? "PDF" : "FILE"}
                              </div>
                            )}
                            <strong>{file.name}</strong>
                            <span style={mutedSmallStyle}>
                              Open zoom preview
                            </span>
                          </button>
                          <button
                            type="button"
                            onClick={() =>
                              updateSelectedDocument(selectedDocument.id, {
                                files: (selectedDocument.files || []).filter(
                                  (item) => item.id !== file.id,
                                ),
                              })
                            }
                            style={tinyDangerButtonStyle}
                          >
                            Remove file
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                ) : (
                  <div style={noticeStyle}>
                    <strong>No file attached.</strong>
                    <p style={mutedSmallStyle}>
                      This record can still hold notes/pasted text. Add a new
                      document if you need to attach a photo, PDF, or file.
                    </p>
                  </div>
                )}
              </div>
            ) : (
              <div style={noticeStyle}>
                <strong>Select a document from the list.</strong>
                <p style={mutedSmallStyle}>
                  After you save a new upload, this info area closes so it is
                  ready for the next item. Click any document to view, edit,
                  zoom, or delete it.
                </p>
                <div style={buttonRowStyle}>
                  <button
                    type="button"
                    onClick={() => setScreen("intake")}
                    style={goldButtonStyle}
                  >
                    Add Document
                  </button>
                  <button
                    type="button"
                    onClick={() => void refreshDocumentVault()}
                    style={secondaryButtonStyle}
                  >
                    Refresh Vault
                  </button>
                </div>
              </div>
            )}
          </div>
        }
      />
    );
  }

  function renderIntake() {
    return (
      <section style={sectionStyle}>
        <SectionHeader
          eyebrow="Phone Intake"
          title="Add Document / Photo"
          detail="Take a photo, upload paperwork, paste notes, and link it directly to the right Atlas section."
          right={
            <button
              type="button"
              onClick={() => setScreen("documents")}
              style={secondaryButtonStyle}
            >
              Documents
            </button>
          }
        />

        <div
          style={
            isMobile
              ? { ...intakeLayoutStyle, gridTemplateColumns: "1fr" }
              : intakeLayoutStyle
          }
        >
          <div style={cardStyle}>
            <div style={eyebrowStyle}>1. Capture or upload</div>
            <h3 style={detailTitleStyle}>Paperwork / Scan</h3>
            <p style={mutedSmallStyle}>
              On your phone, Take Photo opens the camera. Upload handles PDFs,
              screenshots, photos, and other paperwork files.
            </p>

            <div style={buttonRowStyle}>
              <label style={uploadButtonStyle}>
                Take Photo
                <input
                  type="file"
                  accept="image/*"
                  capture="environment"
                  onChange={(event) => {
                    void addIntakeFiles(event.currentTarget.files);
                    event.currentTarget.value = "";
                  }}
                  style={{ display: "none" }}
                />
              </label>
              <label style={secondaryUploadButtonStyle}>
                Upload File(s)
                <input
                  type="file"
                  accept="image/*,.pdf,.txt,.doc,.docx"
                  multiple
                  onChange={(event) => {
                    void addIntakeFiles(event.currentTarget.files);
                    event.currentTarget.value = "";
                  }}
                  style={{ display: "none" }}
                />
              </label>
            </div>

            {intakeFiles.length ? (
              <div style={{ ...photoGridStyle, marginTop: 14 }}>
                {intakeFiles.map((file) => (
                  <div key={file.id} style={photoCardStyle}>
                    {file.dataUrl?.startsWith("data:image/") ? (
                      <img
                        src={file.dataUrl}
                        alt={file.name}
                        style={photoStyle}
                      />
                    ) : (
                      <div style={fileTileStyle}>
                        {file.type?.includes("pdf") ? "PDF" : "FILE"}
                      </div>
                    )}
                    <strong>{file.name}</strong>
                    <div style={buttonRowStyle}>
                      <button
                        type="button"
                        onClick={() => openUploadedFile(file)}
                        style={tinyButtonStyle}
                      >
                        Preview
                      </button>
                      <button
                        type="button"
                        onClick={() => removeIntakeFile(file.id)}
                        style={tinyDangerButtonStyle}
                      >
                        Remove
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div style={emptyStateStyle}>No file attached yet.</div>
            )}
          </div>

          <div style={cardStyle}>
            <div style={eyebrowStyle}>2. Link to Atlas</div>
            <div style={formGridStyle}>
              <Field
                label="Title"
                value={intakeTitle}
                onChange={setIntakeTitle}
                placeholder="Invoice, receipt, photo, estimate, note..."
              />
              <Field
                label="Type"
                value={intakeType}
                onChange={setIntakeType}
                placeholder="Invoice, Manual, Photo, Receipt, Estimate..."
              />
              <label style={{ display: "grid", gap: 6, minWidth: 0 }}>
                <span style={fieldLabelStyle}>Send to section</span>
                <select
                  value={intakeTargetKind}
                  onChange={(event) =>
                    setIntakeTargetKind(
                      event.currentTarget.value as IntakeTargetKind,
                    )
                  }
                  style={inputStyle}
                >
                  {(
                    [
                      "Asset",
                      "Location",
                      "Vendor",
                      "Work Order",
                      "Map Label",
                      "General",
                    ] as IntakeTargetKind[]
                  ).map((kind) => (
                    <option key={kind} value={kind}>
                      {kind}
                    </option>
                  ))}
                </select>
              </label>
              {intakeTargetKind !== "General" ? (
                <label style={{ display: "grid", gap: 6, minWidth: 0 }}>
                  <span style={fieldLabelStyle}>Record</span>
                  <select
                    value={intakeTargetId}
                    onChange={(event) =>
                      setIntakeTargetId(event.currentTarget.value)
                    }
                    style={inputStyle}
                  >
                    {intakeTargetOptions.map((option) => (
                      <option key={option.id} value={option.id}>
                        {option.name}
                      </option>
                    ))}
                  </select>
                </label>
              ) : null}
              <Field
                label="Notes"
                value={intakeNotes}
                onChange={setIntakeNotes}
                multiline
                placeholder="What is this, why it matters, follow-up needed..."
              />
              <Field
                label="Paste text / email / copied paperwork"
                value={intakePastedText}
                onChange={setIntakePastedText}
                multiline
                placeholder="Paste copied text, email content, invoice notes, serial info, etc."
              />
            </div>

            <div style={noticeStyle}>
              <strong>{intakeMessage}</strong>
              <p style={mutedSmallStyle}>
                Saved intake appears in Documents and is linked back to the
                selected record.
              </p>
            </div>

            <div style={buttonRowStyle}>
              <button
                type="button"
                onClick={() => void saveIntakeDocument()}
                style={goldButtonStyle}
              >
                Save to Atlas
              </button>
              <button
                type="button"
                onClick={resetIntakeDraft}
                style={secondaryButtonStyle}
              >
                Clear
              </button>
            </div>
          </div>
        </div>
      </section>
    );
  }

  function renderProcedures() {
    return (
      <ListDrawerLayout
        eyebrow="Procedures"
        title="Procedures"
        isMobile={isMobile}
        list={
          <div style={listStyle}>
            {filteredProcedures.map((procedure) => (
              <button
                key={procedure.id}
                type="button"
                onClick={() => setSelectedProcedureId(procedure.id)}
                style={{
                  ...rowButtonStyle,
                  borderColor:
                    procedure.id === selectedProcedure.id
                      ? colors.gold
                      : colors.line,
                }}
              >
                <div>
                  <strong>{procedure.title}</strong>
                  <p style={mutedSmallStyle}>
                    {procedure.area} · {procedure.steps.length} steps
                  </p>
                </div>
                <span style={badgeStyle(procedure.priority)}>
                  {procedure.priority}
                </span>
              </button>
            ))}
          </div>
        }
        drawer={
          <>
            <h3 style={editorHeaderStyle}>
              {selectedProcedure.title.trim() || "New Procedure"}
            </h3>
            <div style={formGridStyle}>
              <Field
                label="Title"
                value={selectedProcedure.title}
                onChange={(value) => updateProcedure({ title: value })}
              />
              <Field
                label="Area"
                value={selectedProcedure.area}
                onChange={(value) => updateProcedure({ area: value })}
              />
              <SelectField
                label="Priority"
                value={selectedProcedure.priority}
                onChange={(value) => updateProcedure({ priority: value })}
                options={["High", "Normal", "Seasonal"] as const}
              />
              <Field
                label="Steps, one per line"
                value={selectedProcedure.steps.join("\n")}
                onChange={(value) =>
                  updateProcedure({
                    steps: value
                      .split("\n")
                      .map((item) => item.trim())
                      .filter(Boolean),
                  })
                }
                multiline
              />
            </div>
            {isRecordDirty("procedure", selectedProcedure.id) ? (
              <button
                type="button"
                onClick={() =>
                  void saveDirtyRecord(
                    "procedures",
                    selectedProcedure,
                    "procedure",
                    selectedProcedure.id,
                  )
                }
                style={goldButtonStyle}
              >
                Save Procedure
              </button>
            ) : null}
          </>
        }
      />
    );
  }

  function renderParts() {
    return (
      <ListDrawerLayout
        eyebrow="Inventory"
        title="Parts"
        isMobile={isMobile}
        list={
          <div style={listStyle}>
            {filteredParts.map((part) => (
              <button
                key={part.id}
                type="button"
                onClick={() => setSelectedPartId(part.id)}
                style={{
                  ...rowButtonStyle,
                  borderColor:
                    part.id === selectedPart.id ? colors.gold : colors.line,
                }}
              >
                <div>
                  <strong>{part.name}</strong>
                  <p style={mutedSmallStyle}>
                    {part.category} · Qty {part.quantity} / Min{" "}
                    {part.minQuantity}
                  </p>
                </div>
                <span style={badgeStyle(part.status)}>{part.status}</span>
              </button>
            ))}
          </div>
        }
        drawer={
          <>
            <h3 style={editorHeaderStyle}>
              {selectedPart.name.trim() || "New Part"}
            </h3>
            <div style={formGridStyle}>
              <Field
                label="Name"
                value={selectedPart.name}
                onChange={(value) => updatePart({ name: value })}
              />
              <Field
                label="Category"
                value={selectedPart.category}
                onChange={(value) => updatePart({ category: value })}
              />
              <Field
                label="Quantity"
                value={String(selectedPart.quantity)}
                onChange={(value) => updatePart({ quantity: Number(value) })}
              />
              <Field
                label="Minimum Quantity"
                value={String(selectedPart.minQuantity)}
                onChange={(value) => updatePart({ minQuantity: Number(value) })}
              />
              <SelectField
                label="Status"
                value={selectedPart.status}
                onChange={(value) => updatePart({ status: value })}
                options={["In Stock", "Low", "Out", "Order"] as const}
              />
              <Field
                label="Notes"
                value={selectedPart.notes}
                onChange={(value) => updatePart({ notes: value })}
                multiline
              />
            </div>
          </>
        }
      />
    );
  }

